import numpy as np

def two_ply_search(state: int, transitions: dict, value_function: dict, gamma: float) -> dict:
    def one_step_q(s, a):
        """Compute Q(s,a) using one-step lookahead with value function at leaves."""
        outcomes = transitions.get((s, a), [])
        q = 0.0
        for prob, next_s, reward in outcomes:
            leaf_val = value_function.get(next_s, 0.0)
            q += prob * (reward + gamma * leaf_val)
        return q

    def best_value_at(s):
        """Return best Q-value from state s (greedy over available actions)."""
        # Collect all actions available from state s
        actions = {a for (st, a) in transitions if st == s}
        if not actions:
            # Terminal/leaf state: fall back to value function
            return value_function.get(s, 0.0)
        return max(one_step_q(s, a) for a in actions)

    # Find all actions available from the current state
    current_actions = {a for (st, a) in transitions if st == state}
    result = {}

    for action in current_actions:
        outcomes = transitions.get((state, action), [])
        q_two_ply = 0.0
        for prob, next_s, reward in outcomes:
            # Greedy best value two steps ahead
            v_next = best_value_at(next_s)
            q_two_ply += prob * (reward + gamma * v_next)
        result[action] = round(q_two_ply, 4)

    return result

