import numpy as np
from collections import defaultdict

def two_ply_search(state: int, transitions: dict, value_function: dict, gamma: float) -> dict:
    # Pre-index transitions by state for fast lookup
    state_actions = defaultdict(set)
    for (s, a) in transitions:
        state_actions[s].add(a)

    def one_step_q_vec(s, a):
        """Vectorized one-step Q(s,a) using numpy arrays."""
        outcomes = transitions.get((s, a), [])
        if not outcomes:
            return 0.0
        probs = np.array([o[0] for o in outcomes], dtype=np.float64)
        rewards = np.array([o[2] for o in outcomes], dtype=np.float64)
        leaf_vals = np.array([value_function.get(o[1], 0.0) for o in outcomes], dtype=np.float64)
        return float(np.dot(probs, rewards + gamma * leaf_vals))

    def best_value_at(s):
        """Greedy value at state s via vectorized Q computations."""
        actions = list(state_actions.get(s, []))
        if not actions:
            return value_function.get(s, 0.0)
        q_vals = np.array([one_step_q_vec(s, a) for a in actions])
        return float(np.max(q_vals))

    current_actions = list(state_actions.get(state, []))
    result = {}

    for action in current_actions:
        outcomes = transitions.get((state, action), [])
        if not outcomes:
            result[action] = 0.0
            continue
        probs = np.array([o[0] for o in outcomes], dtype=np.float64)
        rewards = np.array([o[2] for o in outcomes], dtype=np.float64)
        v_nexts = np.array([best_value_at(o[1]) for o in outcomes], dtype=np.float64)
        q_two_ply = float(np.dot(probs, rewards + gamma * v_nexts))
        result[action] = round(q_two_ply, 4)

    return result
